    /// <summary>Watchlist recommendation: positive-but-sparse, mixed signs, or holdout collapse.</summary>
    public static string ResolveWatchlistRecommendation(
        decimal validationNet, decimal holdoutNet, int validationHoldoutTrades)
    {
        if (holdoutNet <= -Math.Abs(StressPlusCollapseFloorQuote))
            return "CandidateFailed";
        if (validationNet > 0m && holdoutNet > 0m)
            return validationHoldoutTrades < MinValidationHoldoutTrades ? "NeedsMoreData" : "Watchlist";
        if (validationNet <= 0m && holdoutNet <= 0m)
            return "CandidateFailed";
        return "Park";
    }

    public static string ResolveRecommendation(
        bool allCriteriaPass,
        decimal validationNet,
        decimal holdoutNet,
        int validationHoldoutTrades)
    {
        if (allCriteriaPass)
            return "FreezeForForwardIncubation";
        if (validationNet > 0m && holdoutNet > 0m)
            return validationHoldoutTrades < MinValidationHoldoutTrades ? "NeedsMoreData" : "Watchlist";
        if (validationNet <= 0m && holdoutNet <= 0m)
            return "CandidateFailed";
        return "Park";
    }
}
